// Regenerates src/scanner/fingerprint/fastPairModels.generated.ts from the
// community-maintained Google Fast Pair model-ID table in the Momentum
// firmware's ble_spam app. The table entries are uncopyrightable facts (model
// ID → marketing name) sourced from Google's public Fast Pair registry.
//
//   node scripts/generate-fastpair-models.mjs
//
// Commit the regenerated file.
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

const SOURCE =
  'https://raw.githubusercontent.com/Next-Flip/Momentum-Apps/dev/ble_spam/protocols/fastpair.c';
const OUT = join(
  dirname(fileURLToPath(import.meta.url)),
  '..',
  'src',
  'scanner',
  'fingerprint',
  'fastPairModels.generated.ts'
);

const res = await fetch(SOURCE);
if (!res.ok) throw new Error(`Failed to fetch ${SOURCE}: ${res.status}`);
const source = await res.text();

const entries = new Map();
for (const match of source.matchAll(/\{0x([0-9A-Fa-f]{1,6}),\s*"((?:[^"\\]|\\.)+)"\}/g)) {
  const id = match[1].toLowerCase().padStart(6, '0');
  const name = match[2].replace(/\\(.)/g, '$1').trim();
  if (!entries.has(id)) entries.set(id, name);
}
if (entries.size < 400) {
  throw new Error(`Parsed only ${entries.size} entries — source format likely changed.`);
}

// The table lists byte-order variants of the same product as "Name 2",
// "Name 3", …. Collapse those suffixes when the base name is also present so
// both IDs resolve to the clean marketing name.
const names = new Set(entries.values());
for (const [id, name] of entries) {
  const base = name.replace(/ \d$/, '');
  if (base !== name && names.has(base)) entries.set(id, base);
}

const lines = Array.from(entries.entries())
  .sort(([a], [b]) => a.localeCompare(b))
  .map(([id, name]) => `  '${id}': ${JSON.stringify(name)},`);

const contents = `// AUTO-GENERATED by scripts/generate-fastpair-models.mjs — DO NOT EDIT BY HAND.
// Source: Next-Flip/Momentum-Apps ble_spam fastpair.c (community mirror of the
// Google Fast Pair model registry). Regenerate with:
// node scripts/generate-fastpair-models.mjs

// Google Fast Pair model IDs (3 bytes, lowercase hex) mapped to product names.
export const FAST_PAIR_MODELS: Record<string, string> = {
${lines.join('\n')}
};
`;

writeFileSync(OUT, contents);
console.log(`Wrote ${OUT}: ${entries.size} Fast Pair models.`);
